lass="xl7130002" width="70" style="width: 53pt;">　</td><td class="xl6930002">　</td><td class="xl6630002"></td></tr><tr height="8" style="height: 6pt;"><td height="8" class="xl6630002" style="height: 6pt;"></td><td class="xl7230002">　</td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="21" style="height: 15.6pt;"><td height="21" class="xl6630002" style="height: 15.6pt;"></td><td class="xl7230002">　</td><td colspan="8" class="xl7830002" width="560" style="width: 424pt;">세 당사자가 약정을 설정한다고
  가정한다.</td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="20" style="height: 15pt;"><td height="20" class="xl6630002" style="height: 15pt;"></td><td class="xl7230002">　</td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="125" style="height: 93.6pt;"><td height="125" class="xl6630002" style="height: 93.6pt;"></td><td class="xl7230002">　</td><td colspan="8" class="xl7830002" width="560" style="width: 424pt;">약정에서 A는 의결권의 50%,
  B는 30% 그리고 C는 20%를 보유한다. A, B 그리고 C 사이의 계약상 약정에는 약정과 관련 활동에 대한 결정을 위하여 최소한
  의결권의 75%가 요구된다고 명시한다. A는 어떠한 결정이라도 막을 수 있지만, B의 합의를 필요로 하기 때문에 약정을 지배하지는 못한다.
  관련 활동에 대한 결정을 위해 최소한 의결권의 75%를 요구하는 계약상 약정의 조건은, A와 B 모두 동의해야 약정의 관련 활동에 대한
  결정이 이루어질 수 있기 때문에, A와 B가 약정의 공동지배력을 보유한다는 것을 의미한다.<span>&nbsp;</span></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="20" style="height: 15pt;"><td height="20" class="xl6630002" style="height: 15pt;"></td><td class="xl7230002">　</td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="20" style="height: 15pt;"><td height="20" class="xl6630002" style="height: 15pt;"></td><td class="xl7230002">　</td><td class="xl7730002" width="70" style="width: 53pt;">예시 2</td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="8" style="height: 6pt;"><td height="8" class="xl6630002" style="height: 6pt;"></td><td class="xl7230002">　</td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="43" style="height: 32.4pt;"><td height="43" class="xl6630002" style="height: 32.4pt;"></td><td class="xl7230002">　</td><td colspan="8" class="xl7830002" width="560" style="width: 424pt;">약정에 세 당사자가 있다고
  가정한다.<br>
    약정에서 A는 의결권의 50%, B와 C는 각각 25%를 보유한다.</td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="20" style="height: 15pt;"><td height="20" class="xl6630002" style="height: 15pt;"></td><td class="xl7230002">　</td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="125" style="height: 93.6pt;"><td height="125" class="xl6630002" style="height: 93.6pt;"></td><td class="xl7230002">　</td><td colspan="8" class="xl7830002" width="560" style="width: 424pt;">A, B 그리고 C 사이의
  계약상 약정에는 약정의 관련 활동에 대한 결정을 위하여 최소한 의결권의 75%가 요구된다고 명시한다. A는 어떠한 결정이라도 막을 수
  있지만, B 또는 C의 합의가 필요하기 때문에 약정을 지배하지는 못한다. 이 예시에서 A, B 그리고 C는 집합적으로 약정을 지배한다.
  그러나 하나 이상의 당사자들의 조합은 의결권의 75%를 충족할 수 있다(A와 B 또는 A와 C). 이러한 경우 공동약정이 되려면, 계약상
  약정에 대한 관련 활동을 결정하기 위하여 어떤 당사자들 결합의 전체 동의를 요구하여야 하는지 명시할 필요가 있다.</td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="20" style="height: 15pt;"><td height="20" class="xl6630002" style="height: 15pt;"></td><td class="xl7230002">　</td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="20" style="height: 15pt;"><td height="20" class="xl6630002" style="height: 15pt;"></td><td class="xl7230002">　</td><td class="xl7730002" width="70" style="width: 53pt;">예시 3</td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="8" style="height: 6pt;"><td height="8" class="xl6630002" style="height: 6pt;"></td><td class="xl7230002">　</td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="45" style="height: 33.6pt;"><td height="45" class="xl6630002" style="height: 33.6pt;"></td><td class="xl7230002">　</td><td colspan="8" class="xl7830002" width="560" style="width: 424pt;">약정에서 A와 B가 의결권의
  35%를 각각 보유하고 잔여 의결권의 30%는 널리 분산되어 있다고 가정한다. 관련 활동에 관한 결정은 의결권의 다수결에 의한 승인을
  요구한다.<span>&nbsp;</span></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="20" style="height: 15pt;"><td height="20" class="xl6630002" style="height: 15pt;"></td><td class="xl7230002">　</td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7830002" width="70" style="width: 53pt;"></td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="45" style="height: 33.6pt;"><td height="45" class="xl6630002" style="height: 33.6pt;"></td><td class="xl7230002">　</td><td colspan="8" class="xl7830002" width="560" style="width: 424pt;">A와 B는 계약상 약정에 대한
  관련 활동을 결정하기 위하여 A와 B 모두의 합의를 요구하는 것을 명시한 경우에만, 약정의 공동지배력을 보유한다.</td><td class="xl7330002">　</td><td class="xl6630002"></td></tr><tr height="6" style="height: 4.95pt;"><td height="6" class="xl6630002" style="height: 4.95pt;"></td><td class="xl7430002">　</td><td class="xl7530002" width="70" style="width: 53pt;">　</td><td class="xl7530002" width="70" style="width: 53pt;">　</td><td class="xl7530002" width="70" style="width: 53pt;">　</td><td class="xl7530002" width="70" style="width: 53pt;">　</td><td class="xl7530002" width="70" style="width: 53pt;">　</td><td class="xl7530002" width="70" style="width: 53pt;">　</td><td class="xl7530002" width="70" style="width: 53pt;">　</td><td class="xl7530002" width="70" style="width: 53pt;">　</td><td class="xl7630002">　</td><td class="xl6630002"></td></tr><tr height="6" style="height: 4.95pt;"><td height="6" class="xl6530002" style="height: 4.95pt;"></td><td class="xl6530002"></td><td class="xl6530002"></td><td class="xl6530002"></td><td class="xl6530002"></td><td class="xl6530002"></td><td class="xl6530002"></td><td class="xl6530002"></td><td class="xl6530002"></td><td class="xl6530002"></td><td class="xl6530002"></td><td class="xl6530002"></td></tr><tr height="0" style="display: none;"><td width="7" style="width: 5pt;"></td><td width="7" style="width: 5pt;"></td><td width="70" style="width: 53pt;"></td><td width="70" style="width: 53pt;"></td><td width="70" style="width: 53pt;"></td><td width="70" style="width: 53pt;"></td><td width="70" style="width: 53pt;"></td><td width="70" style="width: 53pt;"></td><td width="70" style="width: 53pt;"></td><td width="70" style="width: 53pt;"></td><td width="7" style="width: 5pt;"></td><td width="7" style="width: 5pt;"></td></tr></table></div></div></body></html></div>

다른 경우, 당사자들은 약정이 구조화된 별도기구의 법적 형식에 의해 부여되는 권리와 의무를 변경하거나 수정하기 위하여 계약상 약정을 사용한다.
